INSERT INTO recipes (name, category, tags, kcal, protein_g, carbs_g, fat_g, servings, ingredients, method, source, is_public) VALUES
  ('Spanish Zucchini Tortilla', 'breakfast', '{high-protein,meal-prep,gluten-free,vegetarian,dairy-free}', 377, 21, 22, 22, 2, '["1 tbsp. olive oil", "1 small potato, peeled,", "chopped", "1 small onion, chopped", "\u00bd small zucchini, thinly sliced", "6 eggs"]'::jsonb, 'Heat oil in a non-stick pan and sear the potato and onion over medium-high heat, for about 4 minutes. Next, add the zucchini and sauté for another 4 minutes. In a bowl, whisk eggs and season with salt and pepper. Transfer the vegetables from the pan into the bowl and mix well. Using the same pan, add the egg mixture on low heat and make sure everything is evenly distributed. After about 3 minutes, run a spatula through the outer edges of the tortilla to make sure it does not stick to the pan. Af', 'High Protein Recipe Pack', true),
  ('Omelet Wraps', 'breakfast', '{low-carb,dairy-free,quick,gluten-free}', 237, 20, 3, 15, 4, '["7 oz. (200g) cottage cheese", "4 handfuls watercress", "1 lemon, peel only", "6 eggs", "\u00bc cup (60ml) soy milk", "1 tsp. mixed herbs", "4 tsp. coconut oil"]'::jsonb, 'Place the cottage cheese, watercress and lemon peel in a high bowl and puree with the hand blender (or food processor) until smooth paste forms. Beat the eggs with the milk and herbs in a separate bowl. Heat 1 tsp. of oil in the medium size frying pan and fry ¼ of the egg over medium heat for 2 minutes until the egg solidifies, then turn around. Bake the other side for ½ minute. Remove the omelet from the pan and set aside. Fry the other omelets with the rest of the oil. To serve, spread the cot', 'High Protein Recipe Pack', true),
  ('Egg & Turkey Stuffed Peppers', 'breakfast', '{high-protein,low-carb,meal-prep,quick,gluten-free}', 329, 43, 11, 12, 4, '["Egg & Turkey", "Stuffed Peppers", "4 eggs", "4 egg whites", "2 tbsp. almond milk", "1 tsp. coconut oil", "1 small onion, chopped", "1 lb. (450g) lean ground turkey", "2 tsp. oregano", "1 tsp. cumin"]'::jsonb, 'Heat oven to 400°F (200°C). Beat the eggs, egg whites and milk, then set aside. Heat the coconut oil in a pan over medium heat. Add the onion and cook for 3 minutes until softened and browned. Add in the turkey, oregano and cumin, season with salt and pepper. Cook until meat is cooked through, about 5 minutes. Then add the spinach, and mix until it wilts about 2 minutes. Increase the heat and add in the eggs. Pull the eggs across the skillet with a spatula. Repeat for about 3 minutes until eggs ', 'High Protein Recipe Pack', true),
  ('Smoked Salmon, Feta & Asparagus Omelet', 'breakfast', '{low-carb,quick,gluten-free,meal-prep}', 302, 20, 6, 21, 2, '["Smoked Salmon, Feta", "& Asparagus Omelet", "4 oz. (125g) asparagus", "1 tsp. coconut oil", "3 large eggs", "5 tbsp. (70ml) milk, plant or", "2 oz. (60g) smoked salmon, cut", "into pieces", "\u00bc cup (30g) feta cheese (or", "brie, camembert), cubed", "4-5 cherry tomatoes, halved", "dill, to serve"]'::jsonb, 'Wash the asparagus, break off the hard ends the discard (they will break themselves in the right place). Cut the softer stalks diagonally to about ½ cm pieces. Boil in lightly salted water for about 2 minutes, then strain and set aside. In a bowl, whisk eggs with the milk, salt and pepper. Add asparagus, salmon and cubed cheese, mix everything well. Heat the oven to 350°F (180°C). Heat the oil in a pan (diameter of approx. 24cm) over medium heat, and pour in the egg mixture. Rearrange the toppin', 'High Protein Recipe Pack', true),
  ('High Protein Blueberry Pancakes', 'breakfast', '{high-protein,low-carb,quick,vegetarian,contains-nuts,gluten-free}', 257, 36, 18, 5, 1, '["High Protein", "Blueberry Pancakes", "\u00bc cup liquid egg whites (around", "4 eggs)", "1 scoop (25g) of vanilla whey", "powder", "\u00bd banana, mashed", "almond milk, if needed", "\u00bc cup (25g) fresh or frozen", "blueberries", "\u00bd tsp. coconut oil"]'::jsonb, 'Whisk together the egg whites and protein powder. Stir in the mashed banana and add the blueberries. If the pancake mixture seems too thick, add a splash of almond milk to thin it. Heat the coconut oil in a pan to low-medium. Pour in the pancake mixture and cook until little bubbles form (about 5 minutes). Make sure the pancake has set enough before you try flipping it, then flip over. Cook the pancake for another 2-3 minutes. You can also make 3 small pancakes instead of 1 large. Serve with you', 'High Protein Recipe Pack', true),
  ('Eggs Fried On Tomatoes With Tuna', 'breakfast', '{high-protein,low-carb,quick,gluten-free,dairy-free}', 307, 32, 8, 15, 1, '["Eggs Fried On", "Tomatoes With Tuna", "1 large tomato", "1 tsp. coconut oil", "2 eggs", "3 oz. (80g) tuna in brine", "pinch of oregano", "pinch of chili flakes"]'::jsonb, 'Peel the tomato and chop into cubes. Heat the oil in a small frying pan, add the chopped tomato and fry over high heat for about 3 minutes. Create 2 gaps in the tomato and break the eggs into them. Season with salt and pepper. Arrange pieces of tuna on top. Then sprinkle with dried oregano and optionally chili flakes. parsley, chopped, to serve Fry for a further 3 minutes or until the egg whites are cooked. Serve with fresh parsley. Tips: • Replace tuna with feta or Gorgonola cheese • For an ext', 'High Protein Recipe Pack', true),
  ('Summer Smoothie Protein Bowl', 'breakfast', '{vegetarian,quick,gluten-free}', 252, 18, 36, 5, 2, '["Summer Smoothie", "Protein Bowl"]'::jsonb, 'Place all ingredients in a high-speed blender and blitz until smooth. Divide between 2 bowls, add your favorite toppings and serve straight away. 2 medium peaches, chopped, frozen 1 medium banana, sliced, frozen ¾ cup (190g) natural yogurt ½ cup (125ml) coconut water 1 scoop (25g) vanilla protein powder Optional toppings: fresh berries Goji berries walnuts chia seeds muesli Note: Toppings are not included in macronutrient information, or shopping list. GF V Q', 'High Protein Recipe Pack', true),
  ('Spinach Shakshuka', 'breakfast', '{low-carb,quick,gluten-free,vegetarian,dairy-free}', 321, 24, 19, 22, 2, '["1 tbsp. coconut oil", "1 large onion, chopped", "2 garlic cloves, crushed", "4 cups (300g) mushrooms,", "sliced", "2 cups (450g) leaf spinach", "4 eggs", "handful parsley, chopped"]'::jsonb, 'Heat the oil in a large pan over medium heat. Add the onion and garlic and cook for 2-3 minutes until soft. Next, add the mushrooms and cook for another 3-4 minutes. Season with salt and pepper. Now start adding the spinach to the pan, you will likely have to do this in batches. Cover the pan with a lid and let it wilt, repeat this step until all the spinach is in the pan. Stir well and taste for seasoning. Make 4 indentations (‘wells’) in the spinach and break an egg in each. Cook for 5-6 minut', 'High Protein Recipe Pack', true),
  ('Salmon Tartar With Avocado & Mango', 'lunch', '{low-carb,dairy-free,quick,gluten-free}', 282, 26, 9, 17, 1, '["Salmon Tartar With", "Avocado & Mango"]'::jsonb, 'Wash and dry the salmon, then cut it into small cubes. Next cut the avocado and mango into cubes and add to the salmon. Mix in the lime juice, chili pepper, and coriander. Season to taste with salt and pepper and mix well. Set aside to chill in the fridge for at least 10 minutes, then serve with toast (not included in nutrition info). 1 small salmon fillet (100g), cut in cubes ¼ avocado, cut in cubes ¼ cup (30g) mango, cut in cubes 1 tbsp. lime juice ⅓ tsp. honey chili pepper, to taste handful c', 'High Protein Recipe Pack', true),
  ('Tuna Salad Lettuce Wraps', 'lunch', '{low-carb,dairy-free,quick,gluten-free}', 286, 38, 14, 9, 2, '["1 \u00bc cup (280g) tuna in olive oil,", "drained"]'::jsonb, 'Put the tuna and half of the oil from the can in a bowl and mix with the tomato puree. 1 tbsp. tomato puree 1 small red onion, finely chopped ½ Granny Smith apple 8 lettuce leaves Chop the red onion as fine as possible and add to the tuna. Cut the apple in 2 parts and remove the core. Chop the apple into small cubes and also add to the tuna. Mix everything. Spread the tuna over the 8 lettuce leaves and serve as wraps. GF DF LC Q', 'High Protein Recipe Pack', true),
  ('Chicken, Orange & Walnut Salad', 'lunch', '{high-protein,quick,gluten-free,contains-nuts,dairy-free}', 458, 28, 47, 20, 2, '["Chicken, Orange &", "Walnut Salad", "For the dressing:", "3 tbsp. of honey", "2 tbsp. mustard", "1 tbsp. olive oil", "1 tbsp. lemon juice", "2 tbsp. orange juice", "\u2153 tsp. cinnamon", "For the salad:", "7 oz. (200g) chicken breast", "4 handfuls rocket", "\u00bc iceberg lettuce", "1 orange", "\u2153 pomegranate fruit, seeds", "\u00bc cup (30g) pecans, roasted"]'::jsonb, 'Peel orange and cut out the pulp and set aside. Squeeze the juice from the rest of the orange and keep it for the sauce. Mix the ingredients of the dressing in a cup, season with salt and pepper. Cut the chicken breast into 4 smaller pieces, season with salt, coat with olive oil and place on a hot grill pan — grill for 4 minutes on both sides. Drizzle the chicken pieces with a tbsp. of dressing and continue to grill for about 1.5 minutes on a slightly lower heat. Turn over then drizzle with anot', 'High Protein Recipe Pack', true),
  ('Salmon & Peach Salad', 'lunch', '{meal-prep,dairy-free,gluten-free,high-protein}', 416, 33, 21, 25, 2, '["For the marinade:", "2 tbsp. apple cider vinegar", "1 tbsp. olive oil", "1 tbsp. tamari", "1 tsp. maple syrup", "\u00bd tsp. ground pepper", "For the salad:", "2 salmon fillets (5oz./140g", "1 cob corn, cooked", "4 oz. (120g) salad leaves"]'::jsonb, 'Combine the apple cider vinegar, olive oil, tamari, maple syrup and ground pepper to make the marinade. Place the salmon skinless-side down in a flat dish, pour over the marinade. Leave it to sit in the fridge for 20-30 minutes. In the meantime, grill the corn in the oven or on a grill pan, then cool slightly and cut off the kernels, set aside. Next, preheat the oven to 400°F (200°C) and place the salmon on a baking tray. Cook for 8-10 minutes or until it is cooked through. Divide the salad leav', 'High Protein Recipe Pack', true),
  ('Tuna & Broccoli Salad With Honey Vinaigrette', 'lunch', '{quick,high-protein}', 328, 21, 26, 14, 2, '["Tuna & Broccoli Salad"]'::jsonb, 'Divide the salad leaves between two plates. Add the sliced radish and pieces of tuna. Toast the bread and cut into cubes, then add to the salad. Place the broccoli in a pot of boiling water and cook for approx. 5 minutes, then strain and add to the salad. In a bowl, mix all the dressing ingredients and drizzle over the salad. Sprinkle with parmesan cheese and serve. For the salad: 2 big handfuls salad leaves 3 radishes, sliced ½ cup (120g) tuna in water, drained 2 slices bread 100g broccoli 2 ts', 'High Protein Recipe Pack', true),
  ('Grilled Chicken & Pineapple Salad', 'lunch', '{dairy-free,quick,gluten-free,high-protein}', 356, 27, 34, 16, 2, '["Grilled Chicken &", "Pineapple Salad", "For the salad:", "7 oz. (200g) chicken breast"]'::jsonb, 'Mix the ingredients of the dressing in a salad bowl, season with salt. Add in the spinach and mint leaves and let it rest. 4 slices pineapple, canned 2 handfuls salad leaves ⅓ cup (10g) mint leaves ½ small onion, finely chopped In the meantime, cut the chicken breasts in half, horizontally (you will end up with 4 chicken fillets), place on a hot grill pan, and cover each chicken breast with a slice of pineapple, season with black pepper. Grill for around 6-8 minutes, then turn and grill for anot', 'High Protein Recipe Pack', true),
  ('Waldorf Chicken Salad', 'lunch', '{high-protein,meal-prep,quick,contains-nuts,gluten-free}', 354, 20, 33, 16, 2, '[]'::jsonb, 'Place the chicken, chopped celery and apple, raisins, and walnuts in a bowl. Add in the mayonnaise, yogurt and lemon juice, season with salt and pepper and mix well. Divide the salad leaves between bowls and top with the filling. Serve with freshly ground black pepper.', 'High Protein Recipe Pack', true),
  ('Tuna & Quinoa Toss Salad', 'lunch', '{meal-prep,quick,gluten-free,high-protein}', 399, 37, 41, 11, 2, '["For the dressing:", "1 tbsp. olive oil", "2 tsp. red wine vinegar", "1 tsp. fresh lemon juice"]'::jsonb, 'Cook quinoa according to instructions on the packaging. Combine the dressing ingredients in a small bowl. Then combine quinoa and the remaining ingredients in a different bowl. 1 tsp. Dijon mustard Drizzle with the dressing and toss gently to coat. salt & pepper, to taste For the salad: 1 cup (185g) cooked quinoa ¼ cup (50g) chickpeas, rinsed and drained ½ cucumber, chopped 1 tbsp. crumbled feta cheese 10 cherry tomatoes, halved 2 cans tuna (7oz./200g drained) GF MP HP Q', 'High Protein Recipe Pack', true),
  ('Post-Workout Potato Pancakes With Cottage Cheese', 'snack', '{vegetarian,quick}', 502, 28, 56, 20, 1, '["Post-Workout Potato Pancakes", "With Cottage Cheese", "For the pancakes:", "\u215d cup (140g) potatoes, peeled", "and grated", "\u00bc cup (50g) zucchini, grated"]'::jsonb, 'Wash, peel and grate the potatoes using the finest grooves. Wash and grate the zucchini as well. Place in a bowl and add in the egg, shallot, dill, flour and salt and pepper. Mix well until combined to make the pancake batter. Heat up a non-stick frying pan and fry small pancakes for 3 minutes, then flip and fry for another 1 minute. Finely chop the radish and the other half of the shallot. Mix in with the dill, cheese, and yogurt. Season to taste with salt and pepper. Serve the pancakes warm wi', 'High Protein Recipe Pack', true),
  ('Miso Salmon With Zucchini Noodles', 'dinner', '{dairy-free,gluten-free}', 496, 29, 27, 30, 2, '["Miso Salmon With", "For the salmon:", "2 salmon fillets, 4.5 oz. (130g) each"]'::jsonb, 'Mix all the salmon marinade ingredients. Coat the salmon fillets in the marinade and refrigerate for at least 20 minutes. 2 tbsp. miso paste 2 tbsp. honey ¼ cup (60ml) tamari, or soy sauce 2 tbsp. ginger, grated 2 tbsp. apple cider vinegar 1 tbsp. sesame oil 2 tsp. sesame seeds For the noodles: In the meantime, place the zucchini noodles and sliced radish in a bowl. Mix all the ingredients for the dressing and pour over the salad. Mix well and refrigerate. Preheat oven to 350°F (180°C). Place th', 'High Protein Recipe Pack', true),
  ('Moroccan Cod & Bulgur Salad', 'lunch', '{dairy-free,high-protein}', NULL, NULL, NULL, NULL, 2, '["Moroccan Cod &", "Bulgur Salad"]'::jsonb, 'Drizzle the cod fillets with lemon juice, then season with salt and pepper. Rub with the garlic, and the rest of the spices and coat with 1 tbsp. of oil. Leave for half an hour to marinade. Cook the bulgur in salted water (about 15 minutes) and once cooked, set aside. Place the chopped tomato in a salad bowl, add in the chopped onion, olives and parsley. Season with salt and pepper, mix and set aside. Heat the pan, and fry the cod for about 3-4 minutes each side, until cooked throughout, then re', 'High Protein Recipe Pack', true),
  ('Turkey & Broccoli Stir Fry', 'dinner', '{dairy-free,quick,gluten-free,high-protein}', 494, 42, 56, 16, 2, '["3.5 oz. (100g) black rice", "noodles", "7 oz. (200g) turkey fillet,", "chopped", "1 broccoli, diced into florets", "1 tbsp. olive oil", "4 tbsp. soy or tamari sauce", "2 tsp. sesame oil", "1 tbsp. rice vinegar", "1 tbsp. grated ginger"]'::jsonb, 'Cook the noodles according to the instructions on the packaging. Strain and rinse with cold water, then set aside. In a wok or deep pan, heat the olive oil and fry the turkey for about 3-4 minutes. Add in the broccoli florets and fry for another 1-2 minutes. Next, pour half a cup of water and 3 tbsp. of soy sauce, then cook until all the water evaporates and the broccoli is tender (about 10 minutes). In the meantime, mix together the remaining soy sauce, sesame oil, vinegar, grated ginger, and m', 'High Protein Recipe Pack', true),
  ('Baked Salmon With Zoodles & Quinoa', 'dinner', '{high-protein,low-carb,quick,gluten-free,dairy-free}', NULL, NULL, NULL, NULL, 2, '["Baked Salmon With", "2 salmon fillets (4.4 oz. /125g", "3.5 oz. (100g) quinoa, cooked", "1 zucchini", "\u00bd tbsp. olive oil", "1 garlic clove, crushed", "2.5 oz. (70g) sundried tomatoes,", "rinsed, chopped", "Salmon marinade:", "2 tbsp. tamari", "\u00bd tbsp. olive oil", "\u00bd tsp. sweet paprika", "\u00bd tsp. hot paprika", "1 tbsp. rice vinegar", "1 tsp. honey", "1 tbsp. black sesame seeds", "chili flakes, to taste"]'::jsonb, 'Mix together the ingredients of the marinade and cover the salmon to marinate for about 1 hour. While the salmon is marinating, cook the quinoa and spiralize the zucchini. Heat the oil in the pan, add the crushed garlic and fry for 1-2 minutes. Add in the zoodles and stir occasionally until it softens (about 3-4 minutes). Towards the end add the chopped tomatoes, and season with salt and pepper, to taste. Heat the oven to 480°F (250°C) and place the salmon on a baking tray or casserole dish. Bak', 'High Protein Recipe Pack', true),
  ('Chicken Thighs With Hoisin Rice', 'dinner', '{high-protein,low-carb,meal-prep,gluten-free,contains-nuts,dairy-free}', 336, 29, 16, 15, 8, '["Chicken Thighs", "With Hoisin Rice", "2 tbsp. coconut oil", "8 skinless chicken thighs"]'::jsonb, 'Preheat the oven to 375°F (190°C). In a large pan, heat the coconut oil. scant 1 cup (200g) jasmine rice 4 spring onions, chopped Season the chicken thighs with salt and pepper and fry for 5 minutes each side until golden brown, then take off the heat and transfer onto a plate. 4 cloves garlic, sliced Pour out most of the fat from the pan, leaving about 1 tbsp. ⅓ cup (200ml) white wine 2 cups (500ml) chicken stock 4 tbsp. dried cranberries For the sauce: 3 tbsp. soy sauce 2 tbsp. of rice vinegar', 'High Protein Recipe Pack', true),
  ('Chinese Pork Stir-Fry With Pineapple', 'dinner', '{meal-prep,dairy-free,gluten-free}', 303, 28, 22, 11, 4, '["Chinese Pork Stir-Fry", "With Pineapple", "14 oz. (400g) pork tenderloin", "1 tbsp. potato starch", "scant \u00bd cup (100g) white rice", "\u2154 cup (135ml) pineapple chucks,", "in juice (keep the juice)", "1 red bell pepper, sliced", "\u00bd onion, sliced", "2 garlic cloves", "\u00bd chili pepper", "1-inch fresh ginger, grated", "2 tbsp. coconut oil", "2 spring onions, chopped, to serve", "For the sauce:", "\u2153 cup (180ml) pineapple juice", "from can", "5 tbsp. soy sauce", "3 tbsp. rice vinegar"]'::jsonb, 'Wash the meat, pat dry, and cut them into the thinnest slices possible. Season with salt and pepper, and coat with potato flour. Cook the rice according to instructions. Drain the pineapple but keep some of the juices for the sauce. Cut the peppers into strips, and the spring onions julienned. Half the chili, remove the seeds, then finely chop. Peel and grate the ginger. Prepare the sauce by mixing all sauce ingredients in a bowl. In a wok or large pan, heat 1 tablespoon of coconut oil, and stir', 'High Protein Recipe Pack', true),
  ('Slow Cooker Chicken Fajitas', 'dinner', '{high-protein,low-carb,meal-prep,gluten-free,dairy-free}', 183, 28, 12, 3, 8, '[]'::jsonb, 'Place half of the sliced peppers and onion in the slow cooker. Layer the chicken and coat with honey, olive oil, lime juice, all the seasonings and chopped tomatoes. Lastly, add the remaining peppers and onions and cook for 4 hours on high. Remove the chicken and shred it with a fork, then return it in in the slow-cooker. Mix well and cook for another 10 mins. on low. Assemble fajitas and enjoy. 2 lbs. (900g) chicken breasts 4 bell peppers, sliced 1 red onion, sliced 2 tbsp. honey 1 tbsp. olive ', 'High Protein Recipe Pack', true),
  ('Creamy Chicken, Mushroom & Tomato Pasta', 'dinner', '{meal-prep,dairy-free}', 385, 35, 26, 14, 3, '["Creamy Chicken, Mushroom", "& Tomato Pasta", "1 \u00bd cup (150g) penne", "12 oz. (350g) chicken breast", "1 tsp. wheat flour", "1 tbsp. olive oil", "1 tsp. dried oregano", "1 small onion, diced", "2 garlic cloves, sliced", "6 sundried tomatoes, chopped", "\u00bd cup (125ml) plant-based oat", "cream (or regular)", "1 bag spinach", "basil leaves, to garnish", "4 cups (300g) mushrooms,", "sliced"]'::jsonb, 'Cook the pasta according to the instructions on the packaging. Chop the chicken fillet, season with salt and pepper and dredge with flour. Heat oil in a large pan and cook chicken over medium heat, then season with oregano. Once the chicken is cooked, remove from the pan and set aside. In the same pan, sauté the onion and sliced garlic. Next, add sliced mushrooms and cook for 5-7 minutes until soft and tender. Add chopped tomatoes and cook for another minute. Place the cooked chicken back into t', 'High Protein Recipe Pack', true),
  ('Cajun Beef & Veg Rice', 'dinner', '{meal-prep,dairy-free,gluten-free}', 503, 40, 55, 13, 3, '["1 tbsp. coconut oil", "3 large carrots, sliced", "2 peppers, sliced", "4 spring onions, sliced", "1 lb. (500g) 5% fat beef mince", "2 tsp. Cajun seasoning", "1 tbsp. tomato pur\u00e9e", "1 lb. (500g) cooked rice"]'::jsonb, 'Heat the oil in a large pan over medium heat. Add the carrots, peppers and white parts of the spring onions. Sauté for 10 minutes until the vegetables start to soften. Add in the minced beef and season with salt and pepper. Cook for 10 minutes, until the meat is browned. Add the Cajun seasoning and tomato purée then stir well. Add in the cooked rice along with 4 tbsp. of water. Stir well to combine all of the ingredients and continue cooking for about 3-4 minutes. Sprinkle with the green parts o', 'High Protein Recipe Pack', true),
  ('Chinese Style Shrimps & Veg', 'dinner', '{meal-prep,dairy-free,gluten-free,high-protein}', 436, 22, 63, 11, 3, '[]'::jsonb, 'Cook the rice according to the instructions on the packaging. In a wok (or large frying pan), heat 1 tbsp. of oil. Sauté the carrots, peppers and garlic for 3 minutes. Then add zucchini and continuously stir for about 5 minutes. Add ginger and season with salt and chili. Move the vegetables to the edge of the pan. Add in the remaining 1 tbsp. of oil and cook the shrimps on the other side of the pan. Fry on high heat, continuously stirring, for about 1 minute. Mix with vegetables and cook for ano', 'High Protein Recipe Pack', true),
  ('Zesty Turkey Meatballs With Couscous Salad', 'lunch', '{meal-prep,high-protein}', 429, 42, 52, 8, 4, '["Zesty Turkey Meatballs", "With Couscous Salad", "For the meatballs:", "2 tbsp. coconut oil", "1 onion, chopped", "\u00bc tsp. chili flakes", "2 garlic cloves, chopped", "1 lb. (500g) turkey thigh mince", "2 handfuls mint leaves, finely", "chopped", "1 lemon, zested and juiced", "7 oz. (200g) 0% fat Greek yogurt", "1 garlic clove, minced"]'::jsonb, 'Heat 1 tbsp. of oil in a frying pan over medium heat, and sauté onion for 5 minutes. Add in the chilies and garlic, then continue for another 1 minute. Transfer to a bowl, and leave to cool for 5 minutes. Next, add the turkey mince, half the mint, half the lemon zest and 1 tbsp. of dry couscous into the bowl. Season with salt and pepper, mix well and shape into 16 meatballs. Pop them in the freezer for 15 minutes. In the meantime, put the couscous in a bowl with the remaining lemon zest. Pour ov', 'High Protein Recipe Pack', true),
  ('Honey & Lime Glazed Salmon With Pineapple Rice', 'dinner', '{dairy-free,gluten-free,high-protein}', 643, 35, 68, 24, 4, '["Honey & Lime Glazed Salmon", "With Pineapple Rice"]'::jsonb, 'Slice the skin off the salmon fillets and discard. Rinse salmon fillets and dry. Marinade: 3 tbsp. honey 3 tbsp. lime juice 3 tbsp. soy sauce 1 tbsp. olive oil 3 tbsp. ginger, grated 2 garlic cloves, crushed Pineapple rice: ⅔ cup (150g) rice ¾ cup (200g) sweetcorn Mix the ingredients of the marinade and coat the pieces of salmon. Place in a casserole and marinate for about 1 hour. Cook the rice in lightly salted water, then spread on a large plate to cool. Drain the sweetcorn and add to the rice', 'High Protein Recipe Pack', true),
  ('Simple Chicken Curry With Saffron Rice', 'dinner', '{dairy-free,gluten-free,high-protein}', NULL, NULL, NULL, NULL, 4, '["Simple Chicken Curry", "With Saffron Rice", "For the chicken:", "8 skinless chicken thighs fillets", "1 tbsp. oil", "1 large onion, diced", "1 tbsp. ginger, minced", "5 cloves garlic, minced", "\u00bd tsp. black pepper", "3 large tomatoes, chopped", "1 \u00bd tsp. turmeric", "For the rice:", "\u00bc cup (60ml) boiling water", "pinch saffron threads (roughly \u215b", "1 cup (225g) basmati rice", "1 tsp. coconut oil", "\u00bd tsp. onion powder", "\u00bc tsp. salt", "1 \u00be cup vegetable stock"]'::jsonb, 'Season the thighs with salt and pepper. Heat the oil in the pan. Fry the thighs on both sides until golden brown. Remove from the pan and set aside. In the same pan sauté the diced onion, garlic and ginger for 3-4 minutes, often stirring — season with pepper and turmeric. Then add chopped tomatoes, and ¼ cup of water, season with salt and bring to a boil. Place the chicken thighs in the simmering sauce, then cover with the lid and cook for about 30-45 minutes or until the meat is tender. 6. In t', 'High Protein Recipe Pack', true),
  ('One Pot Turkey Chili With Rice', 'dinner', '{meal-prep,gluten-free,high-protein}', 295, 31, 21, 9, 4, '["One Pot Turkey", "Chili With Rice", "10 oz. (300g) minced turkey fillet"]'::jsonb, 'Heat the oil in a large pan and sauté the onion and garlic for 3-4 minutes. Next, add the meat and fry for about 5-6 minutes until cooked throughout. Add spices, mix, then add the uncooked rice and mix again. Next add the chopped peppers, beans, corn, canned tomatoes and broth. Mix and bring to a boil. Simmer covered on low heat for about 17-20 minutes. Add grated cheese, cover and heat for another 2 minutes until the cheese melts, then ½ cup (115g) rice 1 medium onion, finely chopped 2 cloves g', 'High Protein Recipe Pack', true),
  ('Baked Salmon Tray With Rice & Tomatoes', 'dinner', '{meal-prep,gluten-free,high-protein}', 476, 31, 44, 19, 4, '["Baked Salmon Tray With", "Rice & Tomatoes", "14 oz. (400g) salmon fillet,  skin", "removed", "1 tsp. honey", "2 tbsp. soy sauce", "2 tbsp. olive oil", "4 slices of lemon + 2 tbsp.      of", "\u215e cup (200g) jasmine rice", "1 cup (150g) cherry tomatoes", "handful basil leaves", "4 tbsp. natural yogurt, 0% fat", "Spices:", "2 tsp. paprika", "\u00bd tsp. curry", "1 tsp. oregano", "pinch of chili flakes"]'::jsonb, 'Cut the salmon fillet into 4 pieces. Rinse, dry and place in a bowl. Season with salt, pepper, paprika, curry, and oregano. Add honey, soy sauce, 2 tbsp. of olive oil and 2 tbsp. of lemon juice. Mix everything and cover the bowl. Preheat oven to 400°F (200°C). Cook the rice according to the instructions on the packaging. Drain it, then transfer into a baking dish and spread the rice over the whole surface of the dish. Place the salmon fillets on top of the rice, add the cherry tomatoes and basil', 'High Protein Recipe Pack', true),
  ('Chicken & Mango Stir Fry', 'dinner', '{high-protein,meal-prep,quick,gluten-free,dairy-free}', 308, 29, 31, 9, 4, '["1 lb. (450g) chicken breasts, cut", "into strips"]'::jsonb, 'Cut the chicken into thin strips and season with salt and pepper, then coat with flour. 1 tbsp. buckwheat flour 1 mango, peeled Peel the mango and cut the flesh into strips. Cut the peppers into strips. Peel the onion and cut into half rings. Cut the deseeded chili pepper lengthwise, then finely chop. 1 red bell pepper, sliced Peel and grate the ginger. 1 red onion, chopped 2 cloves garlic, minced Prepare the sauce by mixing all the sauce ingredients in a bowl. 1 small chili pepper, deseeded and', 'High Protein Recipe Pack', true),
  ('Salmon Teriyaki With Green Beans & Sweetcorn Rice', 'dinner', '{meal-prep,dairy-free,gluten-free,high-protein}', 507, 45, 40, 19, 4, '["Salmon Teriyaki With Green", "Beans & Sweetcorn Rice", "4 salmon fillets (5 oz./150g", "5 oz. (150g) green beans,", "frozen", "1 cup (150g) sweetcorn", "3.5 oz. (100g) brown rice", "2 tbsp. sesame seeds", "1 tbsp. sesame oil", "For the sauce:", "8 tbsp. soy sauce", "3 tbsp. maple syrup", "1 tbsp. lime juice", "4 tbsp. grated ginger", "2 garlic cloves, grated"]'::jsonb, 'Make the marinade by mixing all the sauce ingredients together. Season with salt and pepper. Cut the skin off the salmon then rinse, dry and marinate in the prepared sauce for 1 hour. In the meantime, cook the rice according to the instructions on the packaging. Add the green beans to the cooking rice 4 minutes before it is cooked, then drain. Next, add the sweetcorn and mix well. Preheat the oven to 450°F (230°C). Place the salmon into an oven safe dish, leaving the marinade aside. Bake for 8-1', 'High Protein Recipe Pack', true),
  ('Chicken Orange Stir Fry', 'dinner', '{meal-prep,dairy-free,gluten-free,high-protein}', 397, 34, 53, 7, 4, '["For the sauce:", "1 orange, juice only", "\u2153 cup (100g) marmalade (low sugar)", "\u00bc cup (60ml) soy sauce", "1 tsp. sriracha (or as needed)", "1 tbsp. buckwheat flour", "For the stir fry:", "1 tbsp. coconut oil", "1 lb. (450g) chicken breast, chopped", "1 tbsp. garlic, minced"]'::jsonb, 'Mix all the sauce ingredients together. Add some water if necessary to thin it down slightly. Heat the coconut oil in a large pan over high heat. Add in the chicken breasts and cook for 4-5 minutes until chicken is cooked through. Remove from the pan and set aside. Lower the heat and add the garlic and green onions, cooking for 1 minute. Keep stirring to prevent burning. Now add the mangetout peas and bell pepper and cook for another 3-4 minutes. Add in cooked rice and mix well with the vegetabl', 'High Protein Recipe Pack', true),
  ('Pesto Pasta With Tuna & Almonds', 'dinner', '{contains-nuts,dairy-free,quick,gluten-free}', 512, 24, 69, 16, 4, '["Pesto Pasta With", "Tuna & Almonds", "10.5 oz. (300g) gluten-free", "fusilli", "14 oz. (400g) green beans", "8.4 oz. (240g) tuna in water,", "drained (2 tins)", "1 oz. (30g) roasted almonds,", "chopped", "4.5 oz. (130g) green pesto"]'::jsonb, 'Cook the pasta according to the instructions on the package. In the meantime, halve the green beans and cook in boiling water for about 5 minutes, then drain. Meanwhile, let the tuna drain and chop the almonds coarsely. Drain the pasta and mix with the pesto and green beans. Divide the pasta between bowls and scatter the tuna over it. Garnish with almonds to serve. Season with pepper. GF DF Q N', 'High Protein Recipe Pack', true),
  ('Sweet & Sour Pork Stir-Fry', 'dinner', '{dairy-free,quick,gluten-free}', 446, 22, 52, 16, 4, '["\u215e cup (200g) basmati rice", "10 oz. (300g) pork loin", "2 garlic cloves", "4 spring onions", "1 tbsp. coconut oil", "3 tbsp. ginger syrup", "1 lime, juiced", "1 \u2153 cup (200g) sugar snap", "1 \u00bc cup (250g) cherry", "tomatoes", "1 \u00bc cup (250g) pineapple,", "canned or fresh"]'::jsonb, 'Cook the rice according to instructions on the packaging. In the meantime, cut the pork into slices. Finely chop the garlic and slice the spring onions diagonally. Heat the oil in a wok on high heat, add the pork tenderloin, garlic, ginger syrup, lime juice and season with salt. Stir fry for 2 minutes, then lower the heat and add in the sugar snap peas. Stir fry for another 4 minutes on low heat. Next, add in tomatoes and pineapple and stir fry for another 4 minutes, then take off the heat. Toss', 'High Protein Recipe Pack', true),
  ('Pepper Steak', 'dinner', '{high-protein,low-carb,meal-prep,gluten-free,dairy-free}', 187, 22, 12, 6, 4, '["12 oz. (340g) round beef,", "trimmed", "4 tsp. plus 3 tbsp. soy sauce"]'::jsonb, 'Slice the beef into thin slices. Place in a bowl and add 4 tsp. of soy sauce, 1 tablespoon of rice wine, 1 teaspoon of buckwheat flour and season with freshly ground black pepper. 1 tbsp. rice wine 3 tsp. buckwheat flour 2 tsp. coconut oil 1 large onion, sliced into strips 1 red bell pepper, sliced into strips ½ tsp. black pepper crushed red pepper flakes, to taste In a small bowl, mix 3 tablespoons of soy sauce, 1 tablespoon of water and 2 tsp. buckwheat flour, then set aside. Heat 1 teaspoon o', 'High Protein Recipe Pack', true),
  ('Quick & Easy Meatballs', 'snack', '{low-carb,dairy-free,gluten-free,high-protein}', 309, 36, 9, 14, 4, '["1 lb. (500g) lean ground beef"]'::jsonb, 'Preheat the oven to 400°F (200°C). 1 small onion, finely diced Place all the ingredients apart from the bacon in a 2 garlic cloves, minced 1 red pepper, diced 1 egg ½ cup (30g) buckwheat flour ¼ cup coriander, chopped 1 tsp. oregano 12 slices streaky bacon bowl, season with salt and pepper and mix well using your hands. Once everything is well combined, form 12 meatballs the size of a golf ball (use a ¼ cup for measuring). Wrap each meatball in a slice of bacon and place on a baking sheet. Bake ', 'High Protein Recipe Pack', true),
  ('Quick Beef Chow Mein', 'dinner', '{meal-prep,quick,dairy-free,high-protein}', 325, 28, 33, 10, 4, '["5.5 oz. (160g) egg noodles", "7 oz. (200g) beef tenderloin", "1 tbsp. sesame oil", "1 clove garlic, minced", "1 tbsp. ginger, grated", "\u00bd leek, sliced (mostly white", "parts)", "1 red bell pepper, sliced", "3 mushrooms, sliced"]'::jsonb, 'Prepare the noodles according to instructions on the packaging. Cut the beef into thin strips. Heat the sesame oil in a wok or a large frying pan. Add the garlic and ginger and fry for about a minute. Add the beef and cook for another 2 minutes. Next, add the leeks, pepper and mushrooms and fry for about 5 minutes. Finally, add the cooked noodles, season with pepper and a pinch of sugar. Pour in the soy sauce and water, then stir and fry for another 2 minutes. a pinch of ground white pepper To s', 'High Protein Recipe Pack', true),
  ('Simple Chili & Sweet Potato Chips', 'dinner', '{meal-prep,dairy-free,gluten-free,high-protein}', 382, 29, 33, 16, 4, '["Simple Chili &", "Sweet Potato Chips", "For the potatoes:", "3 medium sweet potatoes", "2 tsp. garlic powder", "1 tsp. onion powder", "2 tbsp. buckwheat flour", "1 tbsp. olive oil", "salt & pepper", "For the simple chili:", "1 lb. (450g) lean ground beef", "1 tbsp. chili flakes", "1 can chopped tomatoes (14oz./", "6 fl. oz. (170ml) water", "For the garnish:", "2 tbsp. coriander, chopped", "1 avocado, mashed"]'::jsonb, 'Heat the oven to 420°F (215°C). Wash the potatoes and cut them into chips. Season the chopped potatoes with the garlic and onion powder, salt and pepper, then sprinkle with buckwheat flour. Drizzle with olive oil and make sure all the potatoes are seasoned. Spread the potatoes on a baking tray, making sure they are not too close together. Bake in the oven for 40 minutes, stirring halfway through. In the meantime, heat a non-stick pan over a medium- high skillet and add the ground beef. Cook for ', 'High Protein Recipe Pack', true),
  ('Cherry Sorbet', 'snack', '{vegetarian,dairy-free,gluten-free}', 109, 2, 24, 1, 4, '["1 \u00be cups (400g) frozen pitted", "cherries", "2 tbsp. honey", "1 tbsp. lemon juice", "4 tbsp. vanilla soy yogurt (e.g.", "Alpro)", "4 tbsp. water", "mint leaves, to serve"]'::jsonb, 'Blitz the frozen cherries in a food processor or high speed blender with the honey, 1 tbsp. of lemon juice, 4 tbsp. of yogurt and 4 tbsp. of water until smooth. Spoon into a freezer-proof container then freeze for 1 hour. Scoop out the sorbet into serving glasses, top with mint and serve immediately. The ingredients will make approx. 8 scoops of sorbet (2 per serving). GF DF V', 'High Protein Recipe Pack', true),
  ('Protein Fruit Bowls', 'snack', '{vegetarian,quick}', 250, 25, 30, 4, 4, '[]'::jsonb, 'Spoon the quark into serving bowls or glasses. Garnish with the toppings and serve. For the mango bowl: 7 oz. (200g) natural quark ¼ mango, chopped 1 tbsp. granola For the strawberry bowl: 7 oz. (200g) natural quark 5 strawberries, halved ½ banana, sliced 1 tbsp. coconut chips V Q', 'High Protein Recipe Pack', true),
  ('Matcha Chia Pudding', 'snack', '{low-carb,gluten-free,vegetarian,contains-nuts,dairy-free}', 275, 23, 19, 9, 2, '["\u00bc cup (30g) chia seeds", "1 \u00bd cup almond milk", "2 tsp. maple syrup", "3 tbsp. (40g) unflavoured soy", "protein isolate (or vanilla)", "1 tsp. matcha", "1 cup (100g) fresh or frozen", "berries, to serve"]'::jsonb, 'Mix the chia seeds and almond milk and place in the fridge. After an hour, mix again and place back in the refrigerator to chill overnight. The next morning, mix in the maple syrup, protein powder, and matcha. Divide between two bowls and serve with berries. GF DF LC V N', 'High Protein Recipe Pack', true),
  ('Raspberry Protein Smoothie', 'snack', '{high-protein,quick,vegetarian,contains-nuts,gluten-free}', 331, 29, 25, 12, 1, '[]'::jsonb, 'Place all ingredients in a high-speed blender and blitz until smooth. ½ ripe banana 1 cup (125g) frozen raspberries 1 cup (240ml) almond milk 2 tbsp. vanilla whey or pea protein 1 tbsp. smooth almond butter handful ice cubes GF HP V Q N', 'High Protein Recipe Pack', true),
  ('Green Glow Protein Smoothie', 'snack', '{high-protein,quick,vegetarian,contains-nuts,gluten-free}', 350, 29, 34, 12, 1, '[]'::jsonb, 'Place all ingredients into a high-speed blender and blitz until smooth. Serve immediately. 1 small banana 1 cup spinach 1 cup kale 1 tbsp. almond butter ⅔ cup (150ml) coconut water 1 scoop (25g) vanilla protein powder, optional Note: The protein powder is optional, but adds a boost of protein. You can use whey or any plant-based protein powder. You can also replace the protein powder with a few tablespoons of Greek yogurt (in that case reduce the amount of liquid). GF HP V Q N', 'High Protein Recipe Pack', true),
  ('Vanilla & Coffee Protein Smoothie', 'snack', '{low-carb,quick,vegetarian,contains-nuts,gluten-free}', 174, 26, 4, 6, 2, '["Protein Smoothie"]'::jsonb, 'Please all in gradients in a high-speed blender and mix until smooth. Serve cold in a glass. ¼ cup (60ml) espresso 1 ⅔ cup (400ml) almond milk 2 scoops vanilla whey 2 tsp. cinnamon 2 tbsp. flax seeds handful ice GF LC V Q N', 'High Protein Recipe Pack', true),
  ('Antioxidant Blueberry Protein Smoothie', 'snack', '{low-carb,quick,vegetarian,contains-nuts,gluten-free}', 197, 26, 14, 4, 1, '["Antioxidant Blueberry", "Protein Smoothie"]'::jsonb, 'Blend all the ingredients in a high-speed blender until smooth and serve. ½ cup (125ml) coconut water ½ cup (125ml) almond milk, unsweetened 1 scoop vanilla whey protein ½ cup (50g) frozen blueberries 1 tsp. ground cinnamon 1 tsp. chia seeds GF LC V Q N', 'High Protein Recipe Pack', true),
  ('Turmeric Poached Egg', 'breakfast', '{low-carb,quick,gluten-free,vegetarian,contains-nuts,dairy-free}', 219, 14, 12, 15, 2, '["2 tsp. pine nuts", "1 \u00be cups (400g) of fresh", "spinach", "\u215d cup (125g) of tomatoes,", "halved", "1 tbsp. mild olive oil", "1 tbsp. white wine vinegar", "1 tsp. ground turmeric", "2 medium-sized eggs"]'::jsonb, 'Heat a dry frying pan and toast the pine nuts for 2 minutes, then set aside. In the meantime, heat the oil in a frying pan and stir fry the spinach and tomatoes for 2 minutes on medium heat until wilted. Season with salt and pepper. Bring a pot of water to the boil and add in the vinegar and turmeric. Turn the heat down so that the water no longer bubbles. Carefully break in the egg and poach for 3 minutes repeat with the second egg. Divide the spinach over two bowls, top with the poached egg an', 'Low Carb Recipe Pack', true),
  ('Omelet With Cottage Cheese & Basil', 'breakfast', '{low-carb,vegetarian,quick,gluten-free}', 200, 15, 3, 14, 4, '["Omelet With Cottage", "Cheese & Basil", "6 large eggs", "4 tbsp. water", "1 tbsp. oil or butter", "1 bunch fresh basil"]'::jsonb, 'Beat the eggs with the water and season with salt and pepper. Heat ¼ oil in a frying pan and bake 1 thin omelet, repeat until you have 4 omelets. Keep them warm under aluminum foil. ⅞ cup (200g) cottage cheese 12 cherry tomatoes Chop the basil finely and mix with the cottage cheese. Season with freshly ground pepper. Cut the tomatoes into quarters. Divide the cottage cheese and tomato over the omelets and roll them up. Cut diagonally and serve immediately. GF LC V Q', 'Low Carb Recipe Pack', true),
  ('Herby Breakfast Sausages', 'breakfast', '{low-carb,dairy-free,quick,gluten-free}', NULL, NULL, NULL, NULL, 8, '["9 oz. (250g) ground pork", "salt and pepper", "2 tbsp. sage, chopped", "2 tbsp. basil, chopped", "1 tbsp. coconut oil"]'::jsonb, 'In a bowl, mix together the pork with salt, pepper, sage, and basil. Combine well and shape into eight sausages. Heat the coconut oil in a large non-stick frying pan and cook the sausages over medium heat until well browned and thoroughly cooked. Serve hot or store in the refrigerator for later. GF DF LC Q', 'Low Carb Recipe Pack', true),
  ('Avocado & Egg Paste', 'snack', '{low-carb,meal-prep,quick,gluten-free,vegetarian,dairy-free}', 298, 11, 9, 24, 2, '["3 boiled eggs", "1 small garlic clove, minced", "1 ripe avocado", "1 tsp. lemon juice", "1 tsp. olive oil", "3 tbsp. coriander leaves,", "chopped"]'::jsonb, 'Boil the eggs (put in warm water and cook 5 and a half minutes after the water has boiled, then pour cold water in the pot and cool). Once cooled, peel and chop into cubes and put in a bowl. Press the garlic, and add to the eggs. Half the avocado, remove the stone and cut the flesh into cubes. Place the avocado and coriander in the bowl. Drizzle with lemon juice and olive oil. Season everything with salt and pepper, and gently mix. Garnish with more coriander. Serve immediately on bread or on it', 'Low Carb Recipe Pack', true),
  ('Cottage Cheese Protein Pancakes', 'breakfast', '{low-carb,vegetarian,quick}', 162, 12, 18, 4, 4, '["Cottage Cheese", "Protein Pancakes", "1 heaped cup (250g) cottage", "cheese", "3 eggs", "1 tsp. of vanilla extract", "1 tbsp. of coconut sugar", "3 heaped tbsp. flour (regular or", "gluten-free)"]'::jsonb, 'Place the cottage cheese into a bowl, add egg yolks (keep the whites separate) and crush everything with a fork. Add in the flour, and mix thoroughly. Whisk the egg whites into a stiff foam and add to the cheese mixture. Gently combine the ingredients. Heat a dry, non-stick pan and fry the pancakes (about 2 tbsp. of batter per pancake) in batches, for about 3 minutes, until the bottom is slightly browned. Turn and cook for another 2 minutes. Suggested Servings: Greek yogurt, honey, and berries L', 'Low Carb Recipe Pack', true),
  ('Tropical Gluten Free Granola', 'breakfast', '{low-carb,meal-prep,gluten-free,vegetarian,contains-nuts,dairy-free}', 173, 4, 10, 14, 7, '["Tropical Gluten", "Free Granola", "1 cup (165g) pineapple, cubed", "5 Medjool dates, pitted and", "roughly chopped", "orange, 2 tbsp. juice", "1 tbsp. vanilla extract", "1 tsp. ground cinnamon", "\u00bc cup (60ml) coconut oil,", "melted", "3 cups (400g) almonds, roughly", "chopped", "1 cup (150g) cashew nuts,", "roughly chopped", "3 cups (90g) unsweetened", "coconut flakes", "\u00bd cup (70g) sunflower seeds", "\u00bd tsp. salt"]'::jsonb, 'Pre-heat oven to 250°F (120°C) and prepare 2 racks lined with baking sheets. In a food processor or high-speed blender, add the pineapple, dates, orange juice, vanilla extract and cinnamon. Blend until smooth. Next, add in the coconut oil and blend again. Set aside. Chop up the almonds and cashew nuts and transfer into a large bowl. Add the coconut flakes, sunflower seeds, salt and mix well. Fold in the pineapple mix into the nuts and mix well until combined. Divide the wet granola between the t', 'Low Carb Recipe Pack', true),
  ('Smoked Mackerel & Egg Paste', 'breakfast', '{low-carb,quick,gluten-free,meal-prep}', 268, 18, 5, 23, 4, '["Smoked Mackerel", "& Egg Paste", "4 eggs, hard boiled", "7 oz. (200g) smoked mackerel", "1 small onion, finely chopped", "4 small pickled gherkins,", "chopped", "2 tbsp. mayonnaise, light", "2 tbsp. natural yogurt (or more", "bunch of chives, chopped"]'::jsonb, 'Boil the eggs, let them cool and peel off the shells, then chop and place in a bowl. Debone and skin the fish, then chop the meat and add to the bowl. Add the finely chopped onion and gherkins into the bowl. Season with salt and freshly ground pepper. Mix with the mayonnaise, yogurt and chopped chives. Serve with bread, fresh veggies, or on its own. GF LC MP Q', 'Low Carb Recipe Pack', true),
  ('Egg Broccoli & Ham Muffins', 'breakfast', '{low-carb,meal-prep,quick,gluten-free,dairy-free}', 102, 10, 4, 6, 6, '["Egg Broccoli", "& Ham Muffins", "\u00bd broccoli", "5 eggs", "1 clove garlic, minced", "pinch of chili flakes, optional", "4 slices ham, chopped", "\u2153 cup (30g) grated cheese"]'::jsonb, 'Preheat the oven to 360°F (180°C). Place the broccoli in a pot of boiling water and cook for approx. 3 minutes. Strain and cut into small pieces. Beat the eggs in a medium size bowl, add the minced garlic and season with salt and pepper, and chili flakes if using. Grease a 6-mould muffin tray with oil or butter, and fill the moulds with evenly divided broccoli, ham, and grated cheese. Pour the beaten eggs into the moulds and bake in the oven for 10-15 minutes, or until eggs have set. Vegetarian ', 'Low Carb Recipe Pack', true),
  ('Egg, Bacon & Avocado Bowl', 'breakfast', '{high-protein,low-carb,quick,gluten-free,dairy-free}', 378, 23, 14, 32, 1, '["Egg, Bacon &", "Avocado Bowl"]'::jsonb, 'Fry the bacon until crisp on a non-stick pan. Let it cool slightly and chop. Combine the bacon, eggs, avocado, onion and bell pepper in a bowl. Season with salt and pepper to serve. 2 bacon medallions 2 hardboiled eggs, chopped ½ large avocado, chopped 1 tbsp. red onion, finely chopped 1 tbsp. red bell pepper, finely chopped sea salt & ground pepper, to taste GF DF LC HP Q', 'Low Carb Recipe Pack', true),
  ('Asian Scrambled Eggs', 'breakfast', '{low-carb,quick,gluten-free,vegetarian,dairy-free}', 270, 19, 5, 14, 1, '["3 eggs", "soy sauce, few drops", "handful coriander, chopped", "\u00bc avocado"]'::jsonb, 'Separate the egg yolks and whites. Mix the yolks with the soy sauce and chopped coriander. On a dry non-stick pan, fry the egg whites until almost done. Take off the heat and add in the egg yolks, stirring well for about half a minute. ½ tsp. black sesame seeds, to serve Serve sprinkled with black sesame seeds, additional coriander (optional) and avocado on the side. GF DF LC V Q', 'Low Carb Recipe Pack', true),
  ('Zucchini Fries', 'snack', '{low-carb,vegetarian,dairy-free}', 177, 5, 14, 12, 4, '[]'::jsonb, 'Preheat oven to 430°F (220°C). Cut zucchini into fry- like pieces. Crack the egg into a bowl and whisk with the milk. Season with salt, pepper, add the crushed garlic, oregano, and thyme. Mix well. 4 tbsp. breadcrumbs On a separate plate, have your breadcrumbs ready. 1 tsp. dried oregano Grease a large baking tray with 1 tbsp. of olive oil. 1 tsp. dried thyme 3 tbsp. olive oil Dip the zucchini in the egg, then roll in the breadcrumbs and place on the baking tray. Place the tray in the preheated ', 'Low Carb Recipe Pack', true),
  ('Tofu Caesar Summer Rolls', 'lunch', '{low-carb,vegetarian,gluten-free,meal-prep}', 191, 5, 8, 10, 4, '["\u215d cup (100g) firm tofu", "1 tbsp. coconut oil", "4 Romaine lettuce leaves,", "shredded", "\u00bd avocado, sliced", "2 tbsp. Parmesan cheese,", "grated", "Caesar salad dressing", "4 rice paper wrappers"]'::jsonb, 'Slice the tofu into two thin rectangles and press using a towel to remove excess moisture. Heat the oil in a pan over medium-high heat and add the tofu. Season generously with salt and pepper. Cook for 4-5 minutes per side, until golden. Remove and let it cool before slicing into 8 strips. Dip one rice paper in a bowl of warm water. Remove when slightly softened and place carefully on a plate lined with a dampened cloth or kitchen towel. Place a few strips of tofu in the centre, top with avocado', 'Low Carb Recipe Pack', true),
  ('Sweetcorn Fritters', 'snack', '{low-carb,quick,gluten-free,vegetarian,dairy-free}', NULL, NULL, NULL, NULL, 8, '["9.8 oz. (280g) organic", "sweetcorn, drained", "bunch coriander, chopped", "1 lemon, zest", "1 cup (120g) buckwheat flour", "\u00be cup (185ml) cold water", "4 tsp. coconut oil"]'::jsonb, 'Place the sweetcorn in a large bowl. Add the chopped coriander and lemon zest, season with salt and pepper. Next, add in the flour and water and mix well until smooth. Heat 2 tsp. of the coconut oil in a large non-stick pan on high heat. Once the pan is hot, ladle in the mixture. Cook the fritters two batches of 4, or divide the oil accordingly if your pan is not big enough (½ tsp. of oil per 1 fritter). Cook for about 2-3 minutes on each side until browned. The batter makes 8 medium sized fritt', 'Low Carb Recipe Pack', true),
  ('Tofu & Green Peas Paste', 'snack', '{low-carb,quick,gluten-free,vegetarian,dairy-free}', 290, 11, 17, 21, 1, '["\u2154 cup (100g) green peas,", "frozen", "\u215c cup (50g) natural tofu", "\u00bc avocado", "1 handful mint leaves", "1 tbsp. olive oil", "1 tbsp. lemon juice"]'::jsonb, 'In a large bowl, place the frozen peas with boiling water and wait a few minutes until defrosted. Then drain and transfer into a blender. Crumble the tofu and add into the peas alongside the avocado, mint, olive oil, and lemon juice. Finally season to taste with salt and pepper. Blitz everything until a paste has formed. If necessary, add some more mint and lemon to adjust the taste. Serve with toast (not included in nutrition info). GF DF LC V Q', 'Low Carb Recipe Pack', true),
  ('Black Bean Hummus', 'snack', '{low-carb,meal-prep,quick,gluten-free,vegetarian,dairy-free}', NULL, NULL, NULL, NULL, 8, '["1x15 oz. (400g) can black", "beans, keep the water from the"]'::jsonb, 'In a food processor, blend until smooth ¼ cup of water from the can of black beans with garlic, olive oil, tahini, lime juice, and spices. 1 garlic clove, minced Add the black beans and blend for another 1-2 2 tbsp. olive oil 2 tbsp. tahini minutes, until creamy and smooth. Serve as a dip with fresh vegetables or crackers. 2 tbsp. lime juice, or more Store in a sealed container in the fridge for up to 1 ½ tsp. cumin ½ tsp. salt ¼ tsp. cayenne pepper week. GF DF LC MP V Q', 'Low Carb Recipe Pack', true),
  ('Kale & Tofu Salad With Peanut Butter Dressing', 'lunch', '{low-carb,quick,gluten-free,vegetarian,contains-nuts,dairy-free}', 195, 13, 15, 11, 4, '["Kale & Tofu Salad With", "Peanut Butter Dressing", "For the salad:", "14 oz. (400g) natural tofu", "3 cups (90g) kale, chopped", "1 cup (100g) purple cabbage,", "shredded", "1 red bell pepper, chopped", "\u2154 cup (30g) carrot, grated", "1 tbsp. coconut oil", "For the dressing:", "3 tbsp. peanut butter", "2 tbsp. coconut milk", "1 tbsp. rice vinegar", "1 tbsp. honey", "1 tbsp. soy sauce", "\u00bd lime, juiced", "\u00bd tsp. chili flakes", "1-2 tbsp. water"]'::jsonb, 'Wrap the tofu in a kitchen cloth and place something heavy on top of it - this will cause the moisture in the tofu to release. In the meantime, prepare your vegetables. Toss the chopped kale, grated carrot and shredded cabbage in a salad bowl. In a small bowl, mix all the dressing ingredients. Heat the coconut oil in a pan. Cut the tofu into strips and season with salt and pepper — fry on medium- high heat for about 5 minutes each side, or until golden brown. Divide the salad between bowls, top ', 'Low Carb Recipe Pack', true),
  ('Smoked Salmon & Strawberry Salad', 'lunch', '{low-carb,quick,gluten-free}', 302, 19, 16, 19, 2, '["Smoked Salmon &", "Strawberry Salad"]'::jsonb, 'Divide the lettuce leaves between two plates. Add the torn smoked salmon and mozzarella balls as well as the strawberries and basil leaves. Mix all the dressing ingredients and drizzle over the salads. Season with freshly ground black pepper and serve. For the salad: 4 handfuls lamb’s lettuce or rocket, or mix', 'Low Carb Recipe Pack', true),
  ('Cucumber, Avocado & Chicken Salad', 'lunch', '{high-protein,low-carb,meal-prep,quick,contains-nuts,gluten-free}', 304, 21, 12, 20, 4, '["Cucumber, Avocado", "& Chicken Salad", "For the salad:", "\u00bd head iceberg lettuce, shredded", "a dozen basil leaves, torn", "1 avocado", "2 tsp. lemon juice", "\u00bd cucumber, peeled", "\u00bc cup (25g) walnuts", "For the chicken:"]'::jsonb, 'Place the iceberg lettuce into a large bowl. Add torn basil leaves and mix. Divide between 2 serving bowls. Season the chicken fillets with salt and rub with olive oil. Heat a dry pan and fry the chicken for 5 minutes on each side. In the meantime, mix the mustard and honey. Grease the top of the fillets with half the sauce, then turn and cook for another 1.5 minutes. Repeat on the other side. Once cooked, cool slightly and chop. 2 chicken breast fillets (around 150g each) Cut the avocado flesh ', 'Low Carb Recipe Pack', true),
  ('Pear, Cured Ham & Walnut Salad', 'lunch', '{high-protein,low-carb,quick,contains-nuts,gluten-free}', 466, 22, 16, 35, 2, '["Pear, Cured Ham &", "Walnut Salad", "bag of rocket", "1 ripe pear, sliced", "3 oz. (100g) blue cheese,", "4 slices cured ham, cut into", "strips", "\u00bc cup (30g) walnuts, chopped"]'::jsonb, 'Divide the rocket between two bowls. Peel the pear, cut into quarters, cut out the seed nests, and slice. Then arrange on the rocket evenly. Add the cubed cheese and the ham. Finally, top with nuts. Mix the dressing ingredients, season with salt and freshly ground pepper, and pour over the salad then serve. Dressing: 1 tbsp. olive oil 2 tsp. lemon juice 1 tbsp. maple syrup GF LC HP Q N', 'Low Carb Recipe Pack', true),
  ('Easy Greek Zoodle Salad', 'lunch', '{low-carb,vegetarian,quick,gluten-free}', 267, 10, 7, 25, 2, '[]'::jsonb, 'Cut the ends of the cucumber and spiralize it into a bowl. Cut the cucumber “noodles” in 2-3 parts, to shorten them. Cut the cherry tomatoes in halves, chop the spring onions, and cut the feta into cubes. Add everything to the cucumber. In a cup or small bowl, mix the ingredients of the dressing, then drizzle over the salad and mix gently. Divide between two plates and serve. This salad is also a perfect side for grilled meats. For the salad: 1 cucumber', 'Low Carb Recipe Pack', true),
  ('Crushed Cucumber Salad With Salmon', 'lunch', '{high-protein,low-carb,quick,gluten-free,dairy-free}', 323, 23, 10, 23, 2, '["Crushed Cucumber Salad", "With Salmon"]'::jsonb, 'Roughly chop the red bell pepper and place in a bowl. Using a meat mallet or a rolling pin, smash the cucumber, then slice into bite-size pieces and transfer into the bowl. Add the sliced garlic and chopped coriander. Mix all the dressing ingredients and drizzle over the cucumber. Mix well and divide between 2 plates. To serve, break the salmon up into pieces and top the cucumber salad — season with freshly ground black pepper. For the salad: 1 red bell pepper, chopped 1 cucumber, crushed, chopp', 'Low Carb Recipe Pack', true),
  ('Healthy Coronation Chicken Salad', 'lunch', '{high-protein,low-carb,meal-prep,quick,gluten-free}', 217, 25, 10, 8, 2, '["Healthy Coronation", "Chicken Salad"]'::jsonb, 'Mix the mayonnaise, yogurt, and curry powder. If needed, add a splash of water to thin the sauce to the consistency you like. Stir in the chicken, apricots, celery and almonds and season to taste with salt and pepper. Serve with a side salad or as a sandwich filling. 1 tbsp. mayonnaise 2 tbsp. Greek yogurt (0% fat) 1 tsp. curry powder (or more, to taste) 5 oz. (150g) cold cooked chicken, chopped (leftover roast chicken is perfect) 6 dried apricots, chopped 1 celery stick, chopped GF MP HP LC Q', 'Low Carb Recipe Pack', true),
  ('Grilled Vegetable Salad With Tuna', 'lunch', '{low-carb,quick,gluten-free,contains-nuts,dairy-free}', 320, 12, 13, 24, 4, '["With Tuna", "1 lemon", "\u00be cup (160g) tuna pieces in", "olive oil", "\u00bd cup (15g) fresh mint", "1 garlic clove, crushed", "2 zucchinis", "2 \u00be cups (350g) asparagus", "\u00bd cup (50g) pistachio nuts,", "peeled and chopped"]'::jsonb, 'Clean the lemon, grate the skin and squeeze out the juice. Drain the tuna, but save the oil for later. Remove the leaves from the sprigs of mint and place in a high cup with the lemon zest, lemon juice, and tuna oil. Add in the garlic and blend until smooth. Season with salt and pepper. Cut the zucchinis into slices and sprinkle with salt and pepper. Heat the grill pan and grill the zucchini for 6 minutes, turning halfway. Then cook the asparagus for 4 minutes, turning halfway. Place the vegetab', 'Low Carb Recipe Pack', true),
  ('Salmon Spring Rolls', 'lunch', '{low-carb,meal-prep,quick,gluten-free,dairy-free}', 154, 13, 4, 10, 4, '["4 sheets rice paper", "fresh coriander", "7 oz. (200g) salmon, cut into 4", "pieces", "1 tbsp. coconut oil", "soy sauce or tamari (GF), to"]'::jsonb, 'Boil a little bit of the water in a pan. Remove from heat, and dip in the rice paper for 30 seconds, one after the other. Remove the sheets from the water and place on a damp cloth. Place a piece of coriander on top of each sheet, cover with a piece of salmon, sprinkle with freshly ground black pepper, and wrap the rice paper around the fish. Heat the oil in the pan, and fry the rolls for 2 minutes, then turn over and cook for another 2-2.5 minutes until they are nicely browned. Put on a paper t', 'Low Carb Recipe Pack', true),
  ('Cod With Creamy Zoodles', 'dinner', '{low-carb,quick,gluten-free,high-protein}', 271, 33, 13, 11, 2, '["For the fish:", "For the fish:", "10 oz. (300g) cod fillets"]'::jsonb, 'Cut the fish so that you have 2 or more pieces of fillet. Season with salt, pepper and spices, then coat with buckwheat flour. 1 tsp. paprika 1 tsp. turmeric 1 tsp. oregano ½ tsp. chili 1 tbsp. buckwheat flour ¼ cup (60ml) vegetable stock ⅓ cup (80ml) cream (dairy or plant based) Heat 2 tbsp. of oil in a frying pan and fry the cod until golden for about 5 minutes, then flip and repeat on the other side. Mix the cream and the hot stock together. Pour into the pan with the cod and bring to a boil,', 'Low Carb Recipe Pack', true),
  ('Jerk Chicken With Cauliflower Rice', 'dinner', '{high-protein,low-carb,meal-prep,quick,gluten-free,dairy-free}', 397, 33, 15, 24, 4, '["Jerk Chicken With", "Cauliflower Rice", "For the marinade:", "1 tsp. dried thyme leaves", "1 tsp. ground allspice", "2 tbsp. brown sugar", "\u00bd tsp. salt", "\u00bd tsp. pepper", "2 tsp. garlic powder", "\u00bd tsp. cinnamon", "\u00bd tsp. cayenne", "2 tbsp. olive oil", "2 tbsp. lime juice", "For the chicken & rice:", "1 lb. (450g) chicken breast", "14 oz. (400g) cauliflower rice", "2 tbsp. coconut oil", "1 onion, diced", "3 garlic cloves, minced"]'::jsonb, 'Combine all marinade ingredients in a bowl or container. Add chicken breasts and turn to coat in the marinade. Leave to marinate for 15 minutes or overnight. Heat the 1 tbsp. of coconut oil in a pan over medium- high heat. Add in the onion and sauté for 3 minutes, until softened. Next, add in the garlic and cauliflower rice, cook for 2 minutes and add in the coconut milk. Cook for about 10 minutes, or until the coconut milk is absorbed, then remove from heat and stir in the lime zest and juice. ', 'Low Carb Recipe Pack', true),
  ('Grilled Lemon Chicken Salad', 'lunch', '{high-protein,low-carb,meal-prep,gluten-free,dairy-free}', 242, 38, 2, 8, 4, '["2 lemons", "1 \u00bd tbsp. oregano", "1 \u00bd tbsp. olive oil", "2 tsp. minced garlic", "4 skinless, boneless chicken", "breasts (around 5 oz. (150g)", "8 oz. (220g) asparagus", "8 green onions, trimmed", "1 tsp. coconut oil", "1 \u00bd tbsp. white wine vinegar"]'::jsonb, 'Heat oven to 400°F (200°C). Grate lemon rinds to equal 2 teaspoons, then halve the lemons and set aside. Combine lemon peel, oregano, oil, and garlic in a large bowl. Add chicken, season with salt and pepper and toss to cover. Place the chicken and halved lemons on a baking tray inside the heated oven and bake for 20-25 minutes, until the chicken is cooked through and browned. Wait until slightly cooled then chop the chicken. Heat the coconut oil in a small pan over medium heat and cook the aspa', 'Low Carb Recipe Pack', true),
  ('Homemade Quinoa Chicken Nuggets', 'dinner', '{low-carb,gluten-free,high-protein}', 224, 33, 10, 6, 4, '["1 lb. (450g) chicken breasts,", "cut into chunks", "1 cup (185g) cooked quinoa", "1 egg, beaten", "\u00bc cup (30g) cup Parmesan,", "grated", "1 tbsp. dried herbs, of choice"]'::jsonb, 'Set oven to 350°F (180°C). Prepare a baking tray covered with baking paper and evenly spread out the cooked quinoa. Bake for around 20-25 minutes, checking often and stirring to avoid burning. Once quinoa is crispy, set aside to cool. Increase the oven temperature to 390°F (200°C). Whisk the egg in a bowl together with the Parmesan and herbs. Prepare a separate plate with the quinoa. Dip the chicken chunks first in the egg, then coat with the quinoa. Place the chicken nuggets on a baking tray co', 'Low Carb Recipe Pack', true),
  ('Sesame & Ginger Beef With Zucchini Noodles', 'dinner', '{high-protein,low-carb,quick,gluten-free,dairy-free}', 242, 25, 10, 12, 4, '["Sesame & Ginger Beef", "\u00bc cup (60ml) reduced sodium", "soy sauce", "1 tbsp. xylitol (or other", "sweetener)", "2 tbsp. rice wine vinegar", "1 lb. (450g) ground lean beef,", "5% fat"]'::jsonb, 'Mix the soy sauce, rice wine vinegar and sweetener in a small bowl and set aside. Heat a dry non-stick pan over medium heat, add the beef and cook for 7-10 minutes, until cooked through. Move the beef to one side of the pan, then add the sesame oil, ginger and garlic. Cook for 1 minute. Add the already prepared sauce and toss the beef to 2 tbsp. sesame oil coat. Cook for 1 minute mixing everything. 1 tbsp. fresh ginger, grated 3 cloves garlic, minced 2 medium zucchinis, spiralized Slightly heat ', 'Low Carb Recipe Pack', true),
  ('Tom Yum Soup With Shrimps', 'dinner', '{low-carb,meal-prep,quick,gluten-free,dairy-free}', 106, 13, 4, 5, 4, '["Tom Yum Soup", "With Shrimps"]'::jsonb, 'Pour the stock into a pot, add the tom yum paste and bring to a boil. Add coconut milk, tomatoes and mushrooms, and cook for about 5 minutes. Next, add the shrimps, and cook for about 1 minute on low heat. Season with fish sauce and lemon juice. Garnish with fresh coriander and chili to serve. 4 cups (1l) vegetable stock 2 tbsp. (30g) Tom yum paste scant ½ cup (100ml) canned coconut milk 1 cup (225g) chopped tomatoes, canned 1 cup (100g) shitake mushrooms, roughly chopped ¾ cup (200g) shrimps 2 ', 'Low Carb Recipe Pack', true),
  ('Warm Salmon & Quinoa Salad', 'lunch', '{high-protein,low-carb,meal-prep,quick,gluten-free,dairy-free}', 325, 28, 17, 26, 4, '["Warm Salmon &", "1 red pepper", "1 tbsp. olive oil", "4 wild salmon fillets", "1 tsp. spices for salmon", "1 \u2153 cup (200g) sugar snaps", "4 cups boiling water (1l)", "1 \u2153 cup (250g) cooked quinoa", "2 handfuls fresh parsley", "2 tbsp. fresh chives"]'::jsonb, 'Preheat the oven to 400°F (200°C). In the meantime, cut the peppers into strips. Heat the oil in a pan on medium heat and stir fry the pepper for 5 minutes. Place the salmon on a tray covered with baking paper, season with spices and cook in the oven for 10 minutes. Place sugar snaps in a colander and pour over the boiling water. Then add the sugar snaps and quinoa to the peppers and heat up for 4 minutes on medium heat. Chop parsley and chives and mix into the quinoa. Serve as a side with the s', 'Low Carb Recipe Pack', true),
  ('Strawberry Protein Muffins', 'snack', '{low-carb,meal-prep,vegetarian,contains-nuts,gluten-free}', NULL, NULL, NULL, NULL, 12, '["1 cup (120g) oat flour", "\u00bc cup (25g) vanilla protein", "powder", "1 tbsp. lemon juice", "zest of \u00bd a lemon", "2 tbsp. stevia", "\u00bd tsp. baking soda", "pinch sea salt", "pinch cinnamon", "1 tbsp. coconut oil, melted", "\u00be cup egg whites (around 3 eggs)", "2 tbsp. unsweetened almond milk", "\u00bd cup (125g) non-fat Greek", "yogurt", "1 tsp. vanilla extract", "\u00bd cup (100g) strawberries,", "chopped into small pieces"]'::jsonb, 'Preheat oven to 350°F (180°C). Mix all dry ingredients, except the chocolate chips, and then mix in all wet ingredients. Stir until a smooth batter is formed, then lightly stir in strawberries and chocolate chips (leave a few aside to top the muffins). Line a muffin tray with muffin liners and spray with oil. Make sure you spray the liners (paper or silicone), or the muffins will stick. Pour the batter evenly into the muffin tin. Drop 3-5 mini chocolate chips on top of each muffin. Bake the muff', 'Low Carb Recipe Pack', true),
  ('Peanut Butter Protein Fluff', 'snack', '{low-carb,quick,vegetarian,contains-nuts,gluten-free}', 244, 9, 9, 20, 2, '["1 cup (250g) full-fat Greek", "yogurt"]'::jsonb, 'Add the yogurt, nut butter and stevia into a small mixing bowl and whisk together using a hand mixer, until fluffy. 2 tbsp. peanut butter or almond butter 2 tsp. stevia favourite garnish (banana, granola, blueberries) Transfer the mix into a bowl and top with your favourite toppings to serve. GF LC V Q N', 'Low Carb Recipe Pack', true),
  ('Low Carb Banana & Strawberry Cake', 'snack', '{low-carb,vegetarian,dairy-free,meal-prep}', 104, 2, 16, 5, 16, '["Low Carb Banana &", "Strawberry Cake", "4 small ripe bananas"]'::jsonb, 'Pre-heat oven to 350°F (180°C). 1 cup (130g) wheat flour Peel the bananas and place them in a food processor ½ cup (60g) buckwheat flour ¼ cup (60ml) coconut oil 2 tbsp. stevia/xylitol 1 egg 1 tsp. baking powder 10 strawberries, halved or high-speed blender. Blitz until smooth. Add in the egg, oil and xylitol, then mix again. Next, add in the flours and baking powder, and blitz until a smooth batter is formed. Transfer the batter into a greased or silicon cake tray. Place the halved strawberries', 'Low Carb Recipe Pack', true),
  ('Healthy Ferrero Rocher', 'snack', '{low-carb,meal-prep,quick,gluten-free,contains-nuts,dairy-free}', NULL, NULL, NULL, NULL, 12, '["1 cup (135g) + 12 hazelnuts", "2 tbsp. cocoa powder", "2 tbsp. agave syrup", "1 tsp. vanilla extract", "pinch of sea salt"]'::jsonb, 'Add 1 cup of hazelnuts into a food processor and blitz until chopped into tiny pieces. Next, add the cacao powder, agave syrup, vanilla extract, sea salt and chocolate. Pulse until all the ingredients start to stick together. If the mixture is too dry, add 1-2 teaspoon of water. 2 tbsp. dark chocolate chunks Roll the mixture into bite-size balls and insert one hazelnut into the centre of each ball. Serve straight away or store in the fridge for later. GF DF LC MP Q N', 'Low Carb Recipe Pack', true),
  ('Fit Almond Energy Balls', 'snack', '{low-carb,meal-prep,quick,gluten-free,contains-nuts,dairy-free}', 178, 6, 8, 14, 6, '["1 cup (120g) almond meal", "2 tbsp. of honey (or maple", "syrup)", "1 tsp. coconut oil, melted", "\u00bd tsp. lemon juice (optional)", "2 tbsp. desiccated coconut or", "poppy seeds"]'::jsonb, 'Place the almond flour into a bowl, add honey and oil and mix well using your hand, pressing firmly. Form 6 balls. You can also add half a teaspoon of lemon juice to break the sweetness. Roll the energy balls in coconut poppy seeds. GF DF LC MP Q N', 'Low Carb Recipe Pack', true),
  ('Mocha Truffles', 'snack', '{low-carb,meal-prep,gluten-free,vegetarian,contains-nuts,dairy-free}', 103, 2, 7, 7, 10, '["3 oz. (100g) of dark chocolate,", "70-80%", "\u2153 cup (80ml) of full-fat coconut", "2 tbsp. coconut sugar", "2 tbsp. instant coffee", "2 tbsp. almond butter", "pinch sea salt", "2 tbsp. cocoa powder, for", "dusting"]'::jsonb, 'Place the chocolate in a bowl and heat in a microwave just until it starts to melt. In a small pot, heat the coconut milk, along with the instant coffee and sugar just until it’s coming to the boil. Next, whisk in the almond butter with a pinch of sea salt, and stir until smooth. Pour the hot coconut milk mixture into the bowl with the chocolate and stir it very gently and slowly until well combined. Fix a layer of clingfilm right over the top of the mixture, to prevent a skin forming and chill ', 'Low Carb Recipe Pack', true),
  ('Vegan Crème Brulee', 'snack', '{low-carb,gluten-free,vegetarian,contains-nuts,dairy-free}', 138, 1, 15, 9, 4, '["1 vanilla pod", "6.7 fl. oz. (200ml) canned", "coconut milk, full fat", "13.5 fl. oz. (400ml) almond", "milk, unsweetened", "4 tbsp. brown sugar", "2 \u00bd tsp. agar-agar"]'::jsonb, 'Cut the vanilla pod with a knife lengthwise. Scrape the marrow out with the tip of the blade and set aside . In a pot, bring the coconut milk, almond milk, half of the brown sugar, agar-agar, the vanilla pod and the marrow to a boil while stirring often. Remove from the heat as soon as it boils and allow to cool to room temperature. Remove the vanilla pod. Divide the mixture over 4 dishes and leave to set in the refrigerator for 1 hour. Sprinkle the crème with the rest of the brown sugar and car', 'Low Carb Recipe Pack', true),
  ('Banana Chocolate Bites', 'snack', '{low-carb,meal-prep,vegetarian,contains-nuts,gluten-free}', NULL, NULL, NULL, NULL, 30, '["3 ripe bananas", "\u2153 cup (85g) natural peanut", "butter", "\u00bd cup (90g) dark chocolate", "2 tsp. coconut oil"]'::jsonb, 'Peel and slice the bananas. Line a tray or chopping board with baking paper. Place about ½ teaspoon of peanut butter onto the banana slices and top with another banana slice to make a little ‘sandwich’. You should be able to make around 30 sandwiches. Place the bananas on the prepared baking paper and store it in the freezer for about 1 hour. Next, melt the chocolate chips and coconut oil in the microwave or using the water bath method. Once the chocolate is melted, dip each frozen banana sandwi', 'Low Carb Recipe Pack', true),
  ('Bacon & Mushroom Hash', 'breakfast', '{}', 378, 27, 36, 14, 1, '["50g (2 slices) bacon, thinly sliced", "80g mushrooms, quartered", "50g red onion, diced", "1/2 sprig rosemary, finely chopped", "1 clove garlic, finely chopped", "120g potato, diced into 1cm cubes", "chilli to taste", "2 eggs", "1 spring onion, thinly sliced", "1 tbsp sriracha sauce"]'::jsonb, 'Cook potatoes in boiling salted water for 5-7 minutes. Heat frying pan, add bacon, onions and mushrooms, fry for 2 minutes. Add cooked potatoes, garlic, chilli and rosemary, fry 2-3 minutes until potatoes are crispy. Make 2 spaces, crack in eggs, cover and cook on low heat 2-3 minutes. Top with spring onions and sriracha.', 'Healthy Recipe Handbook Vol III', true),
  ('Baked Cod with Nduja & Butterbeans', 'dinner', '{gluten-free,dairy-free}', 558, 47, 34, 26, 1, '["130g cod loin", "15g nduja paste", "1 tsp oil", "150g cooked butterbeans, drained", "200g canned chopped tomatoes", "8-10 basil leaves", "1 tsp chopped coriander", "1/2 tbsp olive oil", "1 clove garlic, minced", "1 tsp finely chopped jalape\u00f1o"]'::jsonb, 'Combine marinade ingredients, add half to cod and bake at 180°C for 6-8 minutes. Fry nduja paste in oil for 30 seconds, add beans and cook for a minute. Add tomatoes and basil, cook 2-3 minutes over low heat. Season and serve with cod and remaining marinade on top.', 'Healthy Recipe Handbook Vol III', true),
  ('Beef & Broccoli', 'dinner', '{gluten-free,dairy-free,low-carb}', 314, 36, 11, 14, 3, '["300g frying beef, thinly sliced", "250g broccoli, in small pieces", "5 dried chillies (optional)", "1 tbsp sesame oil", "2 garlic cloves, finely chopped", "5g ginger, finely chopped", "1 tbsp soy sauce", "1/2 tsp ground pepper", "1 tbsp sesame seeds", "1/2 tbsp corn starch", "40g oyster sauce", "1/2 cup water"]'::jsonb, 'Mix marinade, add meat and leave 10-15 minutes. Mix sauce ingredients. Heat sesame oil until almost smoking, add beef and fry over high heat until well browned. Steam or cook broccoli. Add sauce, once thickening add chillies and broccoli, mix well and serve.', 'Healthy Recipe Handbook Vol III', true),
  ('Beef Picadillo', 'dinner', '{gluten-free,dairy-free}', 279, 31, 14, 11, 4, '["500g minced beef (95/5)", "100g white onion, diced", "200g diced bell pepper", "75g chipotle in adobo sauce", "400g canned tomatoes", "300ml water or beef broth", "2 cloves garlic, finely chopped", "1 tbsp smoked paprika", "1 tsp ground cumin", "1 tsp oregano", "1 tbsp oil"]'::jsonb, 'Cook onions in oil for 2-3 minutes. Add meat and cook 6-8 minutes until browned. Add bell peppers for a minute. Add paprika, cumin, garlic and oregano, cook 30 seconds. Blend tomatoes with chipotle and water/broth, add and simmer covered for 30 minutes.', 'Healthy Recipe Handbook Vol III', true),
  ('Cajun Chicken Pasta', 'dinner', '{high-protein}', 567, 48, 60, 15, 1, '["75g penne pasta", "100g chicken breast, cut into small cubes", "125g canned tomatoes", "1/2 tbsp cajun powder", "1/2 tbsp oil", "50g bell pepper, sliced", "1 spring onion, finely sliced", "1 clove garlic, finely chopped", "1/4 cup pasta water", "5g parmesan cheese, grated"]'::jsonb, 'Cook pasta in boiling salted water 10-12 minutes. Mix chicken with cajun spice. Heat oil and fry chicken until cooked. Add garlic and bell pepper, cook 2-3 minutes. Add canned tomatoes, pasta water and cooked pasta. Serve topped with parmesan.', 'Healthy Recipe Handbook Vol III', true);